      'recoup.title':'Recoupment & Vorschüsse','recoup.sub':'Vorschüsse und verrechenbare Kosten, verrechnet mit erzielten Royalties (Lifetime-Saldo).',
      'recoup.artist':'Künstler','recoup.note':'Notiz','recoup.add':'+ Hinzufügen',
      'recoup.advance':'Vorschuss','recoup.cost':'Verrechenbare Kosten',
      'recoup.recoupable':'Verrechenbar','recoup.royalties':'Royalties (Lifetime)','recoup.recouped':'Verrechnet',
      'recoup.unrecouped':'Nicht verrechnet','recoup.payable':'Auszahlbar',
